pub struct CallInfoExtra {
    // C: int funcidx / nyield / nres — overloaded single int field
    pub value: i32,
    // C: struct transferinfo { unsigned short ftransfer, ntransfer }
    pub ftransfer: u16,
    pub ntransfer: u16,
}

