    // C: lua_getfield(L, LUA_REGISTRYINDEX, findex);
    // C: p = (LStream *)lua_touserdata(L, -1);
    // C: if (isclosed(p)) luaL_error(L, "default %s file is closed", findex+IOPREF_LEN);
