fn g_iofile(state: &mut LuaState, key: &[u8], mode: &[u8]) -> Result<usize, LuaError> {
    // C: if (!lua_isnoneornil(L, 1)) { ... }
    if !matches!(state.type_at(1), LuaType::None | LuaType::Nil) {
