                let ci_func = state.get_ci(ci_idx).func;

                // C: for (i = 0; i < narg1; i++) setobjs2s(L, ci->func.p + i, func + i)
                for i in 0..narg1 {
                    let src = state.get_at(func_idx + i as i32).clone();
