        let old_is_lua_func = matches!(old, LuaValue::Function(lua_types::LuaClosure::Lua(_)));
        if old_is_lua_func {
            eprintln!("[set_at STACK2 CLEAR LUA] new={:?} old={:?}", v, old);
        }
    }
    self.stack[i.0 as usize].val = v;
}

